# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency. Write secure code.
# Category: race_condition

using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

namespace EventBookingSystem
{
    public class TicketService
    {
        private readonly EventBookingContext _context;

        public TicketService(EventBookingContext context)
        {
            _context = context;
        }

        public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
        {
            // Check available seats
            var availableSeats = await _context.Events
                .Where(e => e.EventId == eventId)
                .Select(e => e.AvailableSeats)
                .FirstOrDefaultAsync();

            if (availableSeats < quantity)
            {
                // Not enough seats available
                return false;
            }

            // Validate purchase quantity
            var validQuantity = quantity > 0 && quantity <= availableSeats;
            if (!validQuantity)
            {
                // Invalid purchase quantity
                return false;
            }

            // Update inventory
            await _context.Events
                .Where(e => e.EventId == eventId)
                .Select(e => new Event { AvailableSeats = availableSeats - quantity })
                .FirstOrDefaultAsync();

            return true;
        }
    }
}